import{_ as e,c as s,o as a,a4 as t}from"./chunks/framework.ttppV29E.js";const m=JSON.parse('{"title":"Task Assignee","description":"","frontmatter":{},"headers":[],"relativePath":"docs/tasks/assignee.md","filePath":"docs/tasks/assignee.md","lastUpdated":1777969749000}'),o={name:"docs/tasks/assignee.md"},i=t('<h1 id="task-assignee" tabindex="-1">Task Assignee <a class="header-anchor" href="#task-assignee" aria-label="Permalink to &quot;Task Assignee&quot;">​</a></h1><p>The <code>assignee id</code> and <code>assignee type</code> fields represents the user or entity who the task is assigned to at a given point in the workflow. A <code>task-assigned</code> event is published when the assignee changes, but other than that AireFlow itself does not rely on either property for anything, but other systems such as AireFrame can use it.</p><p><code>assignee id</code> and <code>assignee type</code> are optional properties.</p><h2 id="how-it-s-set" tabindex="-1">How it’s set <a class="header-anchor" href="#how-it-s-set" aria-label="Permalink to &quot;How it’s set&quot;">​</a></h2><p>The <code>assignee id</code> and <code>assignee type</code> can be assigned or updated through several mechanisms:</p><ol><li><p><strong>Workflow definition</strong></p><ul><li><code>assignee id</code> and <code>assignee type</code> can be configured for each task in the workflow builder.</li><li>Supports dynamic expressions (e.g. XPath or Liquid), similar to other configurable fields like <code>name</code> or <code>owner</code>.</li></ul></li><li><p><strong>API updates</strong></p><ul><li>The <code>assignee id</code> and <code>assignee type</code> can be modified at runtime via the PATCH API or via a <a href="./../workflows/mutations.html">Mutation</a>.</li></ul></li></ol><h2 id="assignee-type" tabindex="-1">Assignee Type <a class="header-anchor" href="#assignee-type" aria-label="Permalink to &quot;Assignee Type&quot;">​</a></h2><p>When using the assignee to refer to an AireFrame user, the <code>assignee type</code> field should be used to keep track of the type of AireFrame user so the user can be rendered correctly. AireFrame supports the following types:</p><ul><li><strong>User</strong> - Looks up the ID against AireAuth and shows the user’s display name</li><li><strong>Subject</strong> - Looks up the ID against AireFrame subjects and shows the primary field value</li><li><strong>Subject Proxy</strong> - Looks up the ID against AireAuth and shows the user’s display name</li><li><strong>External</strong> - Shows as <code>[Id] (External)</code></li><li><strong>Client Credentials</strong> - Shows as <code>[Id] (System)</code></li><li><strong>System</strong> - Shows as <code>[Id]</code></li><li><strong>Unknown</strong> - Shows as <code>[Id]</code></li></ul><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><ul><li>Task is defined with <code>assignee = User1</code></li><li>Task assignee is updated via the API <code>assignee = User2</code></li><li>Task emits a <code>Task Assigned</code> event</li></ul>',11),n=[i];function r(d,l,c,h,g,p){return a(),s("div",null,n)}const f=e(o,[["render",r]]);export{m as __pageData,f as default};
